#define BLOCK_SIZE 16
#define amb_temp 80.0f

__kernel void hotspot(
    int num_iterations,
    __global const float *power,
    __global const float *temp_src,
    __global float *temp_dst,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int block_start_x = get_global_id(0) * BLOCK_SIZE;
    int block_start_y = get_global_id(1) * BLOCK_SIZE;

    // Local memory for working temperatures across iterations
    float local_temp[BLOCK_SIZE][BLOCK_SIZE];

    // Initialize local_temp from temp_src
    for (int by = 0; by < BLOCK_SIZE; by++) {
        for (int bx = 0; bx < BLOCK_SIZE; bx++) {
            int c = block_start_x + bx;
            int r = block_start_y + by;
            int idx = r * col + c;

            if (c < col && r < row) {
                local_temp[by][bx] = temp_src[idx];
            } else {
                local_temp[by][bx] = 0.0f;
            }
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Perform all iterations
    for (int iter = 0; iter < num_iterations; iter++) {
        for (int by = 0; by < BLOCK_SIZE; by++) {
            for (int bx = 0; bx < BLOCK_SIZE; bx++) {
                int c = block_start_x + bx;
                int r = block_start_y + by;

                if (c >= col || r >= row) continue;

                int idx = r * col + c;
                float temp_c = local_temp[by][bx];
                float delta;

                // Get neighbor temperatures
                float temp_left, temp_right, temp_up, temp_down;

                // Left neighbor
                if (c == 0) {
                    temp_left = temp_c;
                } else if (bx > 0) {
                    temp_left = local_temp[by][bx - 1];
                } else {
                    temp_left = temp_src[idx - 1];
                }

                // Right neighbor
                if (c == col - 1) {
                    temp_right = temp_c;
                } else if (bx < BLOCK_SIZE - 1) {
                    temp_right = local_temp[by][bx + 1];
                } else {
                    temp_right = temp_src[idx + 1];
                }

                // Up neighbor
                if (r == 0) {
                    temp_up = temp_c;
                } else if (by > 0) {
                    temp_up = local_temp[by - 1][bx];
                } else {
                    temp_up = temp_src[idx - col];
                }

                // Down neighbor
                if (r == row - 1) {
                    temp_down = temp_c;
                } else if (by < BLOCK_SIZE - 1) {
                    temp_down = local_temp[by + 1][bx];
                } else {
                    temp_down = temp_src[idx + col];
                }

                // Compute delta based on boundary position - matches original OpenMP logic
                if (r == 0 && c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp_right - temp_c) * Rx_1 +
                        (temp_down - temp_c) * Ry_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else if (r == 0 && c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp_left - temp_c) * Rx_1 +
                        (temp_down - temp_c) * Ry_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else if (r == row - 1 && c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp_left - temp_c) * Rx_1 +
                        (temp_up - temp_c) * Ry_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else if (r == row - 1 && c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp_right - temp_c) * Rx_1 +
                        (temp_up - temp_c) * Ry_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else if (r == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp_right + temp_left - 2.0f * temp_c) * Rx_1 +
                        (temp_down - temp_c) * Ry_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else if (c == col - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp_down + temp_up - 2.0f * temp_c) * Ry_1 +
                        (temp_left - temp_c) * Rx_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else if (r == row - 1) {
                    delta = Cap_1 * (power[idx] +
                        (temp_right + temp_left - 2.0f * temp_c) * Rx_1 +
                        (temp_up - temp_c) * Ry_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else if (c == 0) {
                    delta = Cap_1 * (power[idx] +
                        (temp_down + temp_up - 2.0f * temp_c) * Ry_1 +
                        (temp_right - temp_c) * Rx_1 +
                        (amb_temp - temp_c) * Rz_1);
                }
                else {
                    delta = Cap_1 * (power[idx] +
                        (temp_down + temp_up - 2.0f * temp_c) * Ry_1 +
                        (temp_right + temp_left - 2.0f * temp_c) * Rx_1 +
                        (amb_temp - temp_c) * Rz_1);
                }

                local_temp[by][bx] = temp_c + delta;
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write final results to temp_dst
    for (int by = 0; by < BLOCK_SIZE; by++) {
        for (int bx = 0; bx < BLOCK_SIZE; bx++) {
            int c = block_start_x + bx;
            int r = block_start_y + by;

            if (c < col && r < row) {
                int idx = r * col + c;
                temp_dst[idx] = local_temp[by][bx];
            }
        }
    }
}
